database_ops.query_literal:
MATCH (s:SemanticMemory {memory_id: $sid})
MATCH (e:EpisodicMemory {memory_id: $eid})
CREATE (s)-[:DERIVES_FROM {
    extraction_method: $method,
    confidence: $confidence
}]->(e)

MATCH (s:SemanticMemory {memory_id: $sid})
MATCH (e:EpisodicMemory {memory_id: $tid})
CREATE (s)-[:DERIVES_FROM {
    extraction_method: $method,
    confidence: $confidence
}]->(e)

MATCH (newer:SemanticMemory {memory_id: $sid})
MATCH (older:SemanticMemory {memory_id: $tid})
CREATE (newer)-[:SUPERSEDES {
    reason: $reason,
    temporal_delta: $delta
}]->(older)

MATCH (new_m:SemanticMemory {memory_id: $new_id})
MATCH (old_m:SemanticMemory {memory_id: $old_id})
CREATE (new_m)-[:SUPERSEDES {
    reason: $reason,
    temporal_delta: $delta
}]->(old_m)

MATCH (s:Session {session_id: $session_id}), (m:SemanticMemory {memory_id: $memory_id})
CREATE (s)-[:CONTRIBUTES_TO_SEMANTIC {
    contribution_type: $contribution_type,
    timestamp: $timestamp,
    delta: $delta
}]->(m)

MATCH (s:Session {session_id: $session_id}), (m:ProceduralMemory {memory_id: $memory_id})
CREATE (s)-[:USES_PROCEDURE {
    timestamp: $timestamp,
    success: $success,
    notes: $notes
}]->(m)

CREATE REL TABLE IF NOT EXISTS CONTAINS(
    FROM NODE TO NODE
)

CREATE REL TABLE IF NOT EXISTS FUNCTION_DEFINITION(
    FROM NODE TO NODE
)

CREATE REL TABLE IF NOT EXISTS CLASS_DEFINITION(
    FROM NODE TO NODE
)
